insert_opp() {
  local json="$1"
  local title=$(echo "$json" | python3 -c "import sys,json; print(json.load(sys.stdin)['title'])" 2>/dev/null)
  
  # Check for duplicate first
  local encoded_title=$(python3 -c "import urllib.parse; print(urllib.parse.quote('$title'))" 2>/dev/null)
  local existing=$(curl -s "${SUPABASE_URL}/rest/v1/opportunities?select=id,title&title=eq.${encoded_title}" \
    -H "apikey: ${SUPABASE_KEY}" \
    -H "Authorization: Bearer ${SUPABASE_KEY}" \
    -H "Accept: application/json")
  
  if echo "$existing" | python3 -c "import sys,json; d=json.load(sys.stdin); exit(0 if len(d)>0 else 1)" 2>/dev/null; then
    echo "⏭ SKIPPED (duplicate): $title"
    return
  fi
  
  local http_code=$(curl -s -o /tmp/sb_resp.json -w "%{http_code}" \
    "${SUPABASE_URL}/rest/v1/opportunities" \
    -H "apikey: ${SUPABASE_KEY}" \
    -H "Authorization: Bearer ${SUPABASE_KEY}" \
    -H "Content-Type: application/json" \
    -H "Prefer: return=representation" \
    -H "Accept: application/json" \
    -d "$json")
  if [ "$http_code" = "201" ]; then
    local new_id=$(cat /tmp/sb_resp.json | python3 -c "import sys,json; print(json.load(sys.stdin)[0]['id'])" 2>/dev/null)
    echo "✓ ID $new_id: $title"
  else
    echo "✗ FAILED: $title (HTTP $http_code)"
    cat /tmp/sb_resp.json 2>/dev/null
    echo
  fi
}

